  SELECT TO_NUMBER(TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(RWD_SEQ.NEXTVAL, '0000')))  FROM DUAL

INSERT INTO /* /msp/insertRwdOrder : McpMypageMapper.insertRwdOrder : 자급제 보상서비스 주문 */
MSP_RWD_ORDER (
RWD_SEQ
, RWD_PROD_CD
, RES_NO

  , REQUEST_KEY

, CONTRACT_NUM
, IF_TRGT_CD
, CHN_CD
, IMEI
, BUY_PRIC
, FILE_ID
, FILE_EXT
, FILE_DIR
, REGST_ID
, REGST_DTTM
, IMEI_TWO
, RWD_AUTH_INFO
) VALUES (
#{rwdSeq}
, #{rwdProdCd}
, #{resNo}

  , #{requestKey}

, #{contractNum}
, #{ifTrgtCd}
, #{chnCd}
, #{imei}
, #{buyPric}
, #{fileId}
, UPPER(#{fileExt})
, #{fileDir}
, #{regstId}
, SYSDATE
, #{imeiTwo}
, #{rwdAuthInfo}
)

mapper.select:
SELECT /* /mypage/cntrList : McpMypageMapper.selectCntrList : 자급제 보상서비스 주문 */ A.USERID , A.CNTR_MOBILE_NO , A.SYS_RDATE , B.SVC_CNTR_NO , B.CONTRACT_NUM , A.REP_NO , B.CUSTOMER_ID AS CUST_ID , B.MODEL_NAME , B.MODEL_ID , B.SUB_STATUS , A.CNTR_MOBILE_NO AS unSvcNo , B.USER_SSN AS unUserSSn , (SELECT CUSTOMER_TYPE FROM MSP_JUO_CUS_INFO WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS CSTMR_TYPE , (SELECT CUSTOMER_LINK_NAME FROM MSP_JUO_CUS_INFO WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS userName , B.OPEN_AGNT_CD , B.LST_COM_ACTV_DATE , B.PPPO FROM MCP_USER_CNTR_MNG A, MSP_JUO_SUB_INFO B WHERE UPPER(A.USERID) = UPPER(#{userId}) AND A.SVC_CNTR_NO = B.CONTRACT_NUM
AND A.CUSTOMER_ID = #{customerId}
AND B.SUB_STATUS <> 'C' ORDER BY A.REP_NO ASC

SELECT /* /mypage/selectContractObj : McpMypageMapper.selectContractObj */ CONTRACT_NUM , SVC_CNTR_NO , T1.SUBSCRIBER_NO , T1.USER_SSN , T1.SUB_LINK_NAME , T2.BL_BILLING_METHOD , T2.BAN , T2.BAN_ADR_ZIP , T2.BAN_ADR_PRIMARY_LN , T2.BAN_ADR_SECONDARY_LN , T1.CUSTOMER_ID , T1.SUB_STATUS , T3.CUSTOMER_TYPE FROM MSP_JUO_SUB_INFO T1 , MSP_JUO_BAN_INFO T2 , MSP_JUO_CUS_INFO T3 WHERE 1=1 AND T1.BAN = T2.BAN AND T1.CUSTOMER_ID = T3.CUSTOMER_ID AND SUB_STATUS <> 'C'
AND SUBSCRIBER_NO= TRIM(#{mobileNo})
AND UPPER(REPLACE(SUB_LINK_NAME,' ','')) = UPPER(REPLACE(#{name},' ',''))
AND CONTRACT_NUM = #{contractNum}
AND T1.CUSTOMER_ID = #{customerId}

SELECT /* /mypage/cntrListNmChg : McpMypageMapper.selectCntrListNmChg 현재요금제정보 가져오기 (명의변경) */ A.USERID , A.CNTR_MOBILE_NO , A.SYS_RDATE , B.SVC_CNTR_NO , B.CONTRACT_NUM , A.REP_NO , B.CUSTOMER_ID AS CUST_ID , B.MODEL_NAME , B.MODEL_ID , B.SUB_STATUS , A.CNTR_MOBILE_NO AS unSvcNo , B.USER_SSN AS unUserSSn , C.CSTMR_TYPE , (SELECT CUSTOMER_TYPE FROM MSP_JUO_CUS_INFO WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS CUSTOMER_TYPE , (SELECT CUSTOMER_LINK_NAME FROM MSP_JUO_CUS_INFO WHERE CUSTOMER_ID = B.CUSTOMER_ID AND ROWNUM = 1) AS userName , B.OPEN_AGNT_CD , C.LST_RATE_CD AS SOC , C.LST_RATE_NM AS SOC_NM , NVL((SELECT FREE_DATA_CNT FROM MSP_RATE_MST WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_DATA_CNT , NVL((SELECT FREE_CALL_CNT FROM MSP_RATE_MST WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_CALL_CNT , NVL((SELECT FREE_SMS_CNT FROM MSP_RATE_MST WHERE RATE_CD = C.LST_RATE_CD),'0') AS FREE_SMS_CNT , B.ON_OFF_TYPE , D.COL_DELINQ_STATUS , D.BAN_ADR_ZIP , D.BAN_ADR_PRIMARY_LN , D.BAN_ADR_SECONDARY_LN FROM MCP_USER_CNTR_MNG A , MSP_JUO_SUB_INFO B , MSP_REQUEST_DTL C , MSP_JUO_BAN_INFO D WHERE UPPER(A.USERID) = UPPER(#{userId}) AND A.SVC_CNTR_NO = B.CONTRACT_NUM AND A.SVC_CNTR_NO = C.CONTRACT_NUM(+) AND B.BAN = D.BAN(+) AND B.SUB_STATUS <> 'C'
AND A.CUSTOMER_ID = #{customerId}
AND B.CONTRACT_NUM = #{contractNum}
ORDER BY A.REP_NO ASC

SELECT /* /mypage/selectBanSel : McpMypageMapper.selectBanSel : 청구계정 번호 조회 */
                BAN
  FROM MSP_JUO_SUB_INFO WHERE CONTRACT_NUM =#{contractNum}

mapper.update:
MERGE INTO  /* /mypage/insertSocfailProcMst : McpMypageMapper.insertSocfailProcMst */
MSP_SOCFAIL_PROC_MST
USING   DUAL
ON      (CONTRACT_NUM = #{contractNum} AND PRCS_MDL_IND = #{prcsMdlInd})
WHEN MATCHED THEN
UPDATE SET
SYS_RDATE = SYSDATE
WHEN NOT MATCHED THEN
INSERT (
CONTRACT_NUM             --계약번호
, PRCS_MDL_IND             --처리 모듈 구분
, A_SOC_CODE               --이전 코드 값
, T_SOC_CODE               --이후 코드 값
, A_SOC_AMNT               --변경전 요금제 할인 월정액
, T_SOC_AMNT               --변경후 요금제 할인 월정액
, SUCC_YN                  --성공여부  ==> 성공시 : Y , 실패시 : N
, CHG_TYPE                 --(즉시 : I , 예약 : R)
, SYS_RDATE                --등록일시
, PROC_MEMO                --처리메모
, PROC_YN                  --처리여부
, PROC_ID                  --처리자

  , PROC_DATE                --처리날짜

) VALUES (
#{contractNum}
, #{prcsMdlInd}
, #{aSocCode}
, #{tSocCode}
, #{aSocAmnt}
, #{tSocAmnt}
, #{succYn}
, #{chgType}
, SYSDATE
, #{procMemo}
, #{procYn}
, #{procId}

  , #{procDate}

)
